svg.script:
function handleClick(element) { 
        const adcode = element.getAttribute('data-adcode'); 
        const name = element.getAttribute('data-name'); 
        const centerLng = element.getAttribute('data-center-lng'); 
        const centerLat = element.getAttribute('data-center-lat'); 
        const parentAdcode = element.getAttribute('data-parent-adcode'); 
        const cityInfo = { 
            adcode: adcode, 
            name: name, 
            center_lng: centerLng, 
            center_lat: centerLat, 
            parent_adcode: parentAdcode 
        }; 
        if (typeof Android !== 'undefined' && Android.onCityClicked) { 
            Android.onCityClicked(JSON.stringify(cityInfo)); 
        } else { 
            console.log('City clicked:', cityInfo); 
            alert('点击了: ' + name + ' (adcode: ' + adcode + ')'); 
        } 
    }
